"""Records the recording start and stop times and grabs the robot boot and system time"""
import os
import json
import time
from http_recorder import HttpRecorder

class TimeRecorder(HttpRecorder):
    """TimeRecorder Class"""

    def __init__(self, name, robot, output_dir, root, ui_queue):
        # Call parent
        HttpRecorder.__init__(self, name, None, None, None, None,
                              robot, output_dir, root, ui_queue)
        # Self variables
        self.__filename = 'time_references.json'

    def start(self):
        """Call parent start"""
        super(TimeRecorder, self).start()
        self.has_started = True

    def stop(self):
        """Call parent stop"""
        super(TimeRecorder, self).stop()
        self.has_stopped = True

        # Execute the time script on robot and grab response
        output=""
        (stdin, stdout, stderr) = self.ssh.exec_command('./time')
        for line in stdout:
            output = output + line
        output.strip("\n")
        (boot, utc) = output.split(' ')
        # Get recording start and stop times
        recording_start_time_str = self.recording_start_time.strftime('%Y-%m-%dT%H:%M:%S.%f')[:-3] + 'Z'
        recording_stop_time_str = self.recording_stop_time.strftime('%Y-%m-%dT%H:%M:%S.%f')[:-3] + 'Z'
        recording_start_time_ms = time.mktime(self.recording_start_time.timetuple()) + self.recording_start_time.microsecond/1000000.0
        recording_stop_time_ms = time.mktime(self.recording_stop_time.timetuple()) + self.recording_stop_time.microsecond/1000000.0
        # Write out data to file
        data = {}
        data['robot_boot_time'] = int(boot.strip("\n"))
        data['robot_utc_time'] = int(utc.strip("\n"))
        data['recording_start_time_str'] = str(recording_start_time_str)
        data['recording_stop_time_str'] = str(recording_stop_time_str)
        data['recording_start_time_ms'] = recording_start_time_ms
        data['recording_stop_time_ms'] = recording_stop_time_ms
        fullpath = os.path.join(self.directory, self.__filename)
        # Write to file
        try:
            with open(fullpath, 'w') as datafile:
                json.dump(data, datafile)
        except IOError as err:
            self.update_ui("I/O error({0}): {1}".format(err.errno, err.strerror), 'red')